    private static String resolveProperty(Properties envProps, String key, String defaultValue) {
        String value = System.getenv(key);
        if (value != null && !value.isBlank()) {
            return value;
        }
        return envProps.getProperty(key, defaultValue);
    }

    private static String resolveRequiredProperty(Properties envProps, String key) {
        String value = System.getenv(key);
        if (value != null && !value.isBlank()) {
            return value;
        }
        value = envProps.getProperty(key);
        if (value == null || value.isBlank()) {
            throw new IllegalStateException(
                "Required property '" + key + "' is not set. " +
                "Set it as an environment variable or in the .env file. " +
                "See .env.example for reference."
            );
        }
        return value;
    }

